// ---------------------------------------------------------------------------
// Clay__ARRAY_DEFINE instantiations that appear in cpp-clay's unresolved refs
//
// Each tuple is (type_name, array_name) matching the CLAY__ARRAY_DEFINE(T, N)
// invocation. This expands to:
//   N                  — struct typedef (TypeRef)
//   N_Add              — function
//   N_Allocate_Arena   — function
//   N_Get              — function
//   N_GetCheckCapacity — function (not all types)
//   N_GetValue         — function (int32_t only)
//   N_RemoveSwapback   — function (some types)
//   N_Set              — function
//   N_Set_DontTouchLength — function (some types)
//   NSlice             — struct typedef (some types)
//   NSlice_Get         — function (slice types)
// ---------------------------------------------------------------------------

/// (array_struct_name, has_get_value, has_remove_swapback, has_set_dont_touch,
///  has_get_check_capacity, has_slice)
struct ArrayDef {
    name: &'static str,
    has_get_value: bool,
    has_remove_swapback: bool,
    has_set_dont_touch: bool,
    has_get_check_capacity: bool,
    has_slice: bool,
    has_set: bool,
}

