// ---------------------------------------------------------------------------
// Symbol builder helpers
// ---------------------------------------------------------------------------

fn fn_sym(name: &str) -> ExtractedSymbol {
    ExtractedSymbol {
        name: name.to_string(),
        qualified_name: name.to_string(),
        kind: SymbolKind::Function,
        visibility: Some(Visibility::Public),
        start_line: 0,
        end_line: 0,
        start_col: 0,
        end_col: 0,
        signature: Some(format!("/* clay macro-generated */ void {name}()")),
        doc_comment: None,
        scope_path: None,
        parent_index: None,
    }
}

fn enum_sym(name: &str) -> ExtractedSymbol {
    ExtractedSymbol {
        name: name.to_string(),
        qualified_name: name.to_string(),
        kind: SymbolKind::EnumMember,
        visibility: Some(Visibility::Public),
        start_line: 0,
        end_line: 0,
        start_col: 0,
        end_col: 0,
        signature: Some(format!("/* clay enum constant */ {name}")),
        doc_comment: None,
        scope_path: None,
        parent_index: None,
    }
}

fn struct_sym(name: &str, kind: SymbolKind) -> ExtractedSymbol {
    ExtractedSymbol {
        name: name.to_string(),
        qualified_name: name.to_string(),
        kind,
        visibility: Some(Visibility::Public),
        start_line: 0,
        end_line: 0,
        start_col: 0,
        end_col: 0,
        signature: Some(format!("/* clay type */ typedef struct {name} {name}")),
        doc_comment: None,
        scope_path: None,
        parent_index: None,
    }
}

fn synthesize_file() -> ParsedFile {
    let mut symbols: Vec<ExtractedSymbol> = Vec::new();

    // 1. CLAY__ARRAY_DEFINE expansions
    for def in ARRAY_DEFS {
        let n = def.name;
        // The array struct itself
        symbols.push(struct_sym(n, SymbolKind::Struct));
        // Always present: _Add, _Get, _Allocate_Arena
        symbols.push(fn_sym(&format!("{n}_Add")));
        symbols.push(fn_sym(&format!("{n}_Get")));
        symbols.push(fn_sym(&format!("{n}_Allocate_Arena")));
        if def.has_get_value       { symbols.push(fn_sym(&format!("{n}_GetValue"))); }
        if def.has_remove_swapback { symbols.push(fn_sym(&format!("{n}_RemoveSwapback"))); }
        if def.has_set_dont_touch  { symbols.push(fn_sym(&format!("{n}_Set_DontTouchLength"))); }
        if def.has_get_check_capacity { symbols.push(fn_sym(&format!("{n}_GetCheckCapacity"))); }
        if def.has_set             { symbols.push(fn_sym(&format!("{n}_Set"))); }
        if def.has_slice {
            let slice = format!("{n}Slice");
            symbols.push(struct_sym(&slice, SymbolKind::Struct));
            symbols.push(fn_sym(&format!("{slice}_Get")));
        }
    }

    // 2. CLAY_* enum constants
    for &c in CLAY_ENUM_CONSTANTS {
        symbols.push(enum_sym(c));
    }

    // 3. Public types
    for &(name, kind) in CLAY_TYPES {
        symbols.push(struct_sym(name, kind));
    }

    // 4. Internal functions
    for &f in CLAY_FUNCTIONS {
        symbols.push(fn_sym(f));
    }

    let n = symbols.len();
    ParsedFile {
        path: "ext:clay-ui-synthetics:clay_generated.h".to_string(),
        language: "c".to_string(),
        content_hash: format!("clay-ui-synthetics-{n}"),
        size: 0,
        line_count: 0,
        mtime: None,
        package_id: None,
        symbols,
        refs: Vec::new(),
        routes: Vec::new(),
        db_sets: Vec::new(),
        symbol_origin_languages: vec![None; n],
        ref_origin_languages: Vec::new(),
        symbol_from_snippet: vec![false; n],
        content: None,
        has_errors: false,
        flow: crate::types::FlowMeta::default(),
        connection_points: Vec::new(),
        demand_contributions: Vec::new(),
    }
}

fn synthetic_dep_root() -> ExternalDepRoot {
    ExternalDepRoot {
        module_path: "clay-ui-synthetics".to_string(),
        version: String::new(),
        root: std::path::PathBuf::from("ext:clay-ui-synthetics"),
        ecosystem: TAG,
        package_id: None,
        requested_imports: Vec::new(),
    }
}

/// Probe the project root for `clay.h`.
///
/// cpp-clay distributes the library as a single header at the project root.
/// We also accept it one level deep (e.g., `vendor/clay.h`, `include/clay.h`)
/// so forks that vendor it in a subdirectory are covered too.
fn project_has_clay_header(project_root: &Path) -> bool {
    if project_root.join("clay.h").is_file() {
        return true;
    }
    // One level of subdirectory search to cover vendor/include patterns.
    let Ok(entries) = std::fs::read_dir(project_root) else { return false };
    for entry in entries.flatten() {
        let Ok(ft) = entry.file_type() else { continue };
        if ft.is_dir() && entry.path().join("clay.h").is_file() {
            return true;
        }
    }
    false
}

// ---------------------------------------------------------------------------
// Ecosystem impl
// ---------------------------------------------------------------------------

pub struct ClayUiSyntheticsEcosystem;

impl Ecosystem for ClayUiSyntheticsEcosystem {
    fn id(&self) -> EcosystemId { ID }
    fn kind(&self) -> EcosystemKind { EcosystemKind::Stdlib }
    fn languages(&self) -> &'static [&'static str] { LANGUAGES }

    fn activation(&self) -> EcosystemActivation {
        // Gate on C being present; the clay.h presence check happens in
        // locate_roots so we don't need a file-scan activation variant.
        EcosystemActivation::Any(&[
            EcosystemActivation::LanguagePresent("c"),
            EcosystemActivation::LanguagePresent("cpp"),
        ])
    }

    fn locate_roots(&self, ctx: &LocateContext<'_>) -> Vec<ExternalDepRoot> {
        if !project_has_clay_header(ctx.project_root) {
            return Vec::new();
        }
        vec![synthetic_dep_root()]
    }

    fn walk_root(&self, _dep: &ExternalDepRoot) -> Vec<WalkedFile> {
        Vec::new()
    }

    fn uses_demand_driven_parse(&self) -> bool { true }

    fn parse_metadata_only(&self, _dep: &ExternalDepRoot) -> Option<Vec<ParsedFile>> {
        Some(vec![synthesize_file()])
    }
}

impl ExternalSourceLocator for ClayUiSyntheticsEcosystem {
    fn ecosystem(&self) -> &'static str { TAG }

    fn locate_roots(&self, project_root: &Path) -> Vec<ExternalDepRoot> {
        if !project_has_clay_header(project_root) {
            return Vec::new();
        }
        vec![synthetic_dep_root()]
    }

    fn parse_metadata_only(&self, _project_root: &Path) -> Option<Vec<ParsedFile>> {
        Some(vec![synthesize_file()])
    }
}

